import React, { useState } from "react";
import { Container, Paper, Typography, TextField, Button, Alert, CircularProgress } from "@mui/material";
import { sendOtp, verifyOtp } from "../services/api";
import { useNavigate } from "react-router-dom";

export default function UserLogin() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [otpSent, setOtpSent] = useState(false);
  const [role, setRole] = useState("user"); // default is user login
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSendOtp = async () => {
    setError(""); setLoading(true);
    try {
      const res = await sendOtp(mobile, role);
      if (res.data.success) setOtpSent(true);
    } catch (err) {
      setError(err.response?.data?.message || "Server error");
    } finally {
      setLoading(false);
    }
  };

  const handleVerifyOtp = async () => {
    setError(""); setLoading(true);
    try {
      const res = await verifyOtp(mobile, otp, role);
      if (res.data.success) {
        localStorage.setItem("token", res.data.user?.token || "");
        navigate(role === "user" ? "/user-dashboard" : "/rider-dashboard");
      }
    } catch (err) {
      setError(err.response?.data?.message || "OTP verification failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 4, borderRadius: 3, textAlign: "center", boxShadow: 5 }}>
        <Typography variant="h4" sx={{ mb: 2 }}>User Login</Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        {!otpSent ? (
          <>
            <TextField
              fullWidth
              label="Mobile Number"
              value={mobile}
              onChange={e => setMobile(e.target.value)}
              margin="normal"
            />
            <Button fullWidth variant="contained" onClick={handleSendOtp} disabled={loading}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Send OTP"}
            </Button>
          </>
        ) : (
          <>
            <TextField
              fullWidth
              label="Enter OTP"
              value={otp}
              onChange={e => setOtp(e.target.value)}
              margin="normal"
            />
            <Button fullWidth variant="contained" onClick={handleVerifyOtp} disabled={loading}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Verify OTP"}
            </Button>
          </>
        )}

        <Typography sx={{ mt: 2 }}>
          Don’t have an account?{" "}
          <Button onClick={() => navigate("/user-register")} sx={{ fontWeight: "bold" }}>Sign Up</Button>
        </Typography>

        <Typography sx={{ mt: 1 }}>
          Are you a Rider?{" "}
          <Button onClick={() => navigate("/rider-login")} sx={{ fontWeight: "bold" }}>Rider Login</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
